func TestE2EInvitationPaginationAdvance(t *testing.T) {
	client, db := setupE2EServer(t)

	// Three rows, then walk two pages of two — keyset pagination must not
	// repeat a row across the page boundary (page1 ∩ page2 = ∅).
	for i := 0; i < 3; i++ {
		// UNIQUE-columned fields must vary per row or the insert 409s.
		raw, err := json.Marshal(seededCreateInvitationRequest(t, db))
		require.NoError(t, err)
		var body map[string]any
		require.NoError(t, json.Unmarshal(raw, &body))
		if s, ok := body["resource_type"].(string); ok {
			body["resource_type"] = s + "-" + strconv.Itoa(i)
		}
		if s, ok := body["resource_id"].(string); ok {
			body["resource_id"] = s + "-" + strconv.Itoa(i)
		}
		if s, ok := body["relation"].(string); ok {
			body["relation"] = s + "-" + strconv.Itoa(i)
		}
		if s, ok := body["identifier"].(string); ok {
			body["identifier"] = s + "-" + strconv.Itoa(i)
		}
		if s, ok := body["token_hash"].(string); ok {
			body["token_hash"] = s + "-" + strconv.Itoa(i)
		}
		client.Post(t, "/invitations", body).RequireStatus(t, 201)
	}

	page1 := client.Get(t, "/invitations?limit=2")
	page1.RequireStatus(t, 200)
	cursor := page1.String(t, "pagination.next_cursor")
	require.NotEmpty(t, cursor, "a full first page must yield a next cursor")

	page2 := client.Get(t, "/invitations?limit=2&cursor="+url.QueryEscape(cursor))
	page2.RequireStatus(t, 200)

	seen := map[string]bool{}
	for _, row := range page1.Data(t) {
		if m, ok := row.(map[string]any); ok {
			seen[toStr(m["invitation_id"])] = true
		}
	}
	advanced := false
	for _, row := range page2.Data(t) {
		m, ok := row.(map[string]any)
		if !ok {
			continue
		}
		pk := toStr(m["invitation_id"])
		assert.False(t, seen[pk], "row %s appears on both pages", pk)
		advanced = true
	}
	assert.True(t, advanced, "second page should contain the remaining row")
}

